def safe_int(s, default=0):
    # BUG: a bare except swallows EVERYTHING, including the
    # TypeError from safe_int(None) and any other real bug.
    # Rewrite it to catch ONLY ValueError, so int('abc') falls
    # back to default but int(None) still raises loudly.
    try:
        return int(s)
    except:
        return default

print(safe_int("42", -1))
